// Embedded viewmodel assets (base64) so the game works from file:// and inside the .neu bundle.
// handsFBX: CS:GO karambit fade + sport/vice gloves, one rigged FBX (knife + both arms).
// gloveLeftPNG/gloveRightPNG: sport glove diffuse textures (the FBX references them externally).
const MODELS={
handsFBX:"",
gloveLeftPNG:"",
gloveRightPNG:""
};
function b64ToBuf(b){const s=atob(b),a=new Uint8Array(s.length);for(let i=0;i<s.length;i++)a[i]=s.charCodeAt(i);return a.buffer;}
